#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e6+10,M=6e6+10;const LL INF=0x3f3f3f3f3f3f3f3fll;
int head[N],des[M],nxt[M],cgt=1,s,t,n,m,h2[N],que[N],H,T,dep[N];LL cap[M];
inline void ins(const int &x,const int &y,const int &z)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=z;
}
inline int F(const int &x,const int &y){return (x-1)*m+y;}
inline bool bfs()
{
	memset(dep,0,(t+1)<<2);dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
}
inline LL dfs(const int &u=s,LL in=INF)
{
	if(u==t)return in;LL out=0;
	for(int &i=h2[u];i;i=nxt[i])if(cap[i]&&dep[des[i]]==dep[u]+1)
	{
		LL tmp=dfs(des[i],min(in,cap[i]));
		cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
	}
	return out?out:dep[u]=0;
}
int main()
{
//	freopen("catch.in","r",stdin);
//	freopen("catch.out","w",stdout);
	n=read();m=read();s=1;t=n*m;
	rep(1,n,i)rep(2,m,j)ins(F(i,j-1),F(i,j),read());
	rep(2,n,i)rep(1,m,j)ins(F(i-1,j),F(i,j),read());
	rep(2,n,i)rep(2,m,j)ins(F(i-1,j-1),F(i,j),read());
	LL ans=0;while(bfs())memcpy(h2,head,(t+1)<<2),ans+=dfs();
	printf("%lld\n",ans);return 0;
}
